  5→} from '@/core/utils/extensionContext';
  6→import { isGeminiEnterpriseEnvironment } from '@/core/utils/gemini';
  7→import { startFormulaCopy } from '@/features/formulaCopy';
  8→import { initI18n } from '@/utils/i18n';
  9→
 10→import { startChatWidthAdjuster } from './chatWidth/index';
 11→import { startContextSync } from './contextSync';
 12→import { startDeepResearchExport } from './deepResearch/index';
 13→import DefaultModelManager from './defaultModel/modelLocker';
 14→import { startEditInputWidthAdjuster } from './editInputWidth/index';
 15→import { startExportButton } from './export/index';
 16→import { startAIStudioFolderManager } from './folder/aistudio';
 17→import { startFolderManager } from './folder/index';
 18→import { startFolderSpacingAdjuster } from './folderSpacing/index';
 19→import { startGemsHider } from './gemsHider/index';
 20→import { startInputCollapse } from './inputCollapse/index';
 21→import { initKaTeXConfig } from './katexConfig';
 22→import { startMarkdownPatcher } from './markdownPatcher/index';
 23→import { startMermaid } from './mermaid/index';
 24→import { startPromptManager } from './prompt/index';
 25→import { startQuoteReply } from './quoteReply/index';
 26→import { startRecentsHider } from './recentsHider/index';
 27→import { startSendBehavior } from './sendBehavior/index';
 28→import { startSidebarAutoHide } from './sidebarAutoHide';
 29→import { startSidebarWidthAdjuster } from './sidebarWidth';
 30→import { startTimeline } from './timeline/index';
 31→import { startTitleUpdater } from './titleUpdater';
 32→import { startWatermarkRemover } from './watermarkRemover/index';
 33→
 34→// Suppress Vite's CSS preload errors in the Chrome extension content script context.
 35→// Dynamic imports (e.g., mermaid) trigger Vite's __vitePreload helper which tries to
 36→// create <link> elements with paths like "/assets/foo.css". In a content script, these
 37→// resolve to the web page origin (e.g., https://gemini.google.com/assets/foo.css)
 38→// instead of the extension, causing false "Unable to preload CSS" errors.
 39→// The CSS is already injected via contentStyle.css, so these preloads are unnecessary.
 40→window.addEventListener('vite:preloadError', (event) => {
 41→  event.preventDefault();
 42→});
 43→
 44→/**
 45→ * Staggered initialization to prevent "thundering herd" problem when multiple tabs
 46→ * are restored simultaneously (e.g., after browser restart).
 47→ *
 48→ * Background tabs get a random delay (3-8s) to distribute initialization load.
 49→ * Foreground tabs initialize immediately for good UX.
 50→ *
 51→ * This prevents triggering Google's rate limiting when restoring sessions with
 52→ * many Gemini tabs containing long conversations.
 53→ */
 54→
 55→// Initialization delay constants (in milliseconds)
 56→const HEAVY_FEATURE_INIT_DELAY = 100; // For resource-intensive features (Timeline, Folder)
 57→const LIGHT_FEATURE_INIT_DELAY = 50; // For lightweight features
 58→const BACKGROUND_TAB_MIN_DELAY = 3000; // Minimum delay for background tabs
 59→const BACKGROUND_TAB_MAX_DELAY = 8000; // Maximum delay for background tabs (3000 + 5000)
 60→
 61→let initialized = false;
 62→let initializationTimer: number | null = null;
 63→let folderManagerInstance: Awaited<ReturnType<typeof startFolderManager>> | null = null;
 64→
 65→let promptManagerInstance: Awaited<ReturnType<typeof startPromptManager>> | null = null;
 66→let quoteReplyCleanup: (() => void) | null = null;
 67→let sendBehaviorCleanup: (() => void) | null = null;
 68→
 69→/**
 70→ * Check if current hostname matches any custom websites
 71→ */
 72→async function isCustomWebsite(): Promise<boolean> {
 73→  try {
 74→    const result = await chrome.storage?.sync?.get({ gvPromptCustomWebsites: [] });
 75→    const customWebsites = Array.isArray(result?.gvPromptCustomWebsites)
 76→      ? result.gvPromptCustomWebsites
 77→      : [];
 78→
 79→    // Normalize current hostname
 80→    const currentHost = location.hostname.toLowerCase().replace(/^www\./, '');
 81→
 82→    console.log('[Gemini Voyager] Checking custom websites:', {
 83→      currentHost,
 84→      customWebsites,
 85→      hostname: location.hostname,
 86→    });
 87→
 88→    const isCustom = customWebsites.some((website: string) => {
 89→      const normalizedWebsite = website.toLowerCase().replace(/^www\./, '');
 90→      const matches =
 91→        currentHost === normalizedWebsite || currentHost.endsWith('.' + normalizedWebsite);
 92→      console.log('[Gemini Voyager] Comparing:', { currentHost, normalizedWebsite, matches });
 93→      return matches;
 94→    });
 95→
 96→    console.log('[Gemini Voyager] Is custom website:', isCustom);
 97→    return isCustom;
 98→  } catch (e) {
 99→    if (isExtensionContextInvalidatedError(e)) {
100→      return false;
101→    }
102→    console.error('[Gemini Voyager] Error checking custom websites:', e);
103→    return false;
104→  }
105→}
106→
107→/**
108→ * Initialize all features sequentially to reduce simultaneous load
109→ */
110→async function initializeFeatures(): Promise<void> {
111→  if (initialized) return;
112→  initialized = true;
113→
114→  try {
115→    if (!hasValidExtensionContext()) {
116→      return;
117→    }
118→    // Sequential initialization with small delays between features
119→    // to further reduce simultaneous resource usage
120→    const delay = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));
121→
122→    // Check if this is a custom website (only prompt manager should be enabled)
123→    const isCustomSite = await isCustomWebsite();
124→
125→    if (isCustomSite) {
126→      // Only start prompt manager for custom websites
127→      console.log('[Gemini Voyager] Custom website detected, starting Prompt Manager only');
128→
129→      promptManagerInstance = await startPromptManager();
130→      return;
131→    }
132→
133→    console.log('[Gemini Voyager] Not a custom website, checking for Gemini/AI Studio');
134→
135→    const isEnterprise = isGeminiEnterpriseEnvironment(
136→      {
137→        hostname: location.hostname,
138→        pathname: location.pathname,
139→        search: location.search,
140→        hash: location.hash,
141→      },
142→      document,
143→    );
144→
145→    if (isEnterprise) {
146→      console.log('[Gemini Voyager] Gemini Enterprise detected, starting Prompt Manager only');
147→      promptManagerInstance = await startPromptManager();
148→      return;
149→    }
150→
151→    if (location.hostname === 'gemini.google.com') {
152→      // Timeline is most resource-intensive, start it first
153→      startTimeline();
154→      await delay(HEAVY_FEATURE_INIT_DELAY);
155→
156→      folderManagerInstance = await startFolderManager();
157→      await delay(HEAVY_FEATURE_INIT_DELAY);
158→
159→      startFolderSpacingAdjuster('gemini');
160→      await delay(LIGHT_FEATURE_INIT_DELAY);
161→
162→      startChatWidthAdjuster();
163→      await delay(LIGHT_FEATURE_INIT_DELAY);
164→
165→      startEditInputWidthAdjuster();
166→      await delay(LIGHT_FEATURE_INIT_DELAY);
167→
168→      startSidebarWidthAdjuster();
169→      await delay(LIGHT_FEATURE_INIT_DELAY);
170→
171→      startSidebarAutoHide();
172→      await delay(LIGHT_FEATURE_INIT_DELAY);
173→
174→      startInputCollapse();
175→      await delay(LIGHT_FEATURE_INIT_DELAY);
176→
177→      startFormulaCopy();
178→
179→      await delay(LIGHT_FEATURE_INIT_DELAY);
180→
181→      // Quote Reply - conditionally start based on storage setting
182→      const quoteReplyResult = await new Promise<{ gvQuoteReplyEnabled?: boolean }>((resolve) => {
183→        try {
184→          chrome.storage?.sync?.get({ gvQuoteReplyEnabled: true }, resolve);
185→        } catch {
186→          resolve({ gvQuoteReplyEnabled: true });
187→        }
188→      });
189→      if (quoteReplyResult.gvQuoteReplyEnabled !== false) {
190→        quoteReplyCleanup = startQuoteReply();
191→      }
192→      await delay(LIGHT_FEATURE_INIT_DELAY);
193→
194→      // Watermark remover - based on gemini-watermark-remover by journey-ad
195→      // https://github.com/journey-ad/gemini-watermark-remover
196→      // Skip on Safari due to fetch interceptor limitations in extension sandbox
197→      if (!isSafari()) {
198→        startWatermarkRemover();
199→      }
200→      await delay(LIGHT_FEATURE_INIT_DELAY);
201→
202→      startTitleUpdater();
203→      await delay(LIGHT_FEATURE_INIT_DELAY);
204→
205→      startDeepResearchExport();
206→      await delay(LIGHT_FEATURE_INIT_DELAY);
207→
208→      startContextSync();
209→      await delay(LIGHT_FEATURE_INIT_DELAY);
210→
211→      // Send behavior (Ctrl+Enter to send)
212→      sendBehaviorCleanup = await startSendBehavior();
213→      await delay(LIGHT_FEATURE_INIT_DELAY);
214→
215→      // Recents hider - hide/show toggle for recent items section
216→      startRecentsHider();
217→      await delay(LIGHT_FEATURE_INIT_DELAY);
218→
219→      // Gems hider - hide/show toggle for Gems list section
220→      startGemsHider();
221→      await delay(LIGHT_FEATURE_INIT_DELAY);
222→
223→      // Markdown Patcher - fixes broken bold tags due to HTML injection
224→      startMarkdownPatcher();
225→      await delay(LIGHT_FEATURE_INIT_DELAY);
226→
227→      // Default Model Manager
228→      DefaultModelManager.getInstance().init();
229→      await delay(LIGHT_FEATURE_INIT_DELAY);
230→    }
231→
232→    if (
233→      location.hostname === 'gemini.google.com' ||
234→      location.hostname === 'aistudio.google.com' ||
235→      location.hostname === 'aistudio.google.cn'
236→    ) {
237→      promptManagerInstance = await startPromptManager();
238→      await delay(HEAVY_FEATURE_INIT_DELAY);
239→
240→      // Initialize Mermaid rendering (lightweight)
241→      startMermaid();
242→      await delay(LIGHT_FEATURE_INIT_DELAY);
243→    }
244→
245→    if (location.hostname === 'aistudio.google.com' || location.hostname === 'aistudio.google.cn') {
246→      startAIStudioFolderManager();
247→      await delay(HEAVY_FEATURE_INIT_DELAY);
248→
249→      startFolderSpacingAdjuster('aistudio');
250→      await delay(LIGHT_FEATURE_INIT_DELAY);
251→
252→      // Formula copy support for AI Studio
253→      startFormulaCopy();
254→      await delay(LIGHT_FEATURE_INIT_DELAY);
255→    }
256→
257→    startExportButton();
258→  } catch (e) {
259→    if (isExtensionContextInvalidatedError(e)) {
260→      return;
261→    }
262→    console.error('[Gemini Voyager] Initialization error:', e);
263→  }
264→}
265→
266→/**
267→ * Determine initialization delay based on tab visibility
268→ */
269→function getInitializationDelay(): number {
270→  // Check if tab is currently visible
271→  const isVisible = document.visibilityState === 'visible';
272→
273→  if (isVisible) {
274→    // Foreground tab: initialize immediately for good UX
275→    console.log('[Gemini Voyager] Foreground tab detected, initializing immediately');
276→    return 0;
277→  } else {
278→    // Background tab: add random delay to distribute load across multiple tabs
279→    const randomRange = BACKGROUND_TAB_MAX_DELAY - BACKGROUND_TAB_MIN_DELAY;
280→    const randomDelay = BACKGROUND_TAB_MIN_DELAY + Math.random() * randomRange;
281→    console.log(
282→      `[Gemini Voyager] Background tab detected, delaying initialization by ${Math.round(randomDelay)}ms`,
283→    );
284→    return randomDelay;
285→  }
286→}
287→
288→/**
289→ * Handle tab visibility changes
290→ */
291→function handleVisibilityChange(): void {
292→  if (document.visibilityState === 'visible' && !initialized) {
293→    // Tab became visible before initialization completed
294→    // Cancel any pending delayed initialization and start immediately
295→    if (initializationTimer !== null) {
296→      clearTimeout(initializationTimer);
297→      initializationTimer = null;
298→      console.log('[Gemini Voyager] Tab became visible, initializing immediately');
299→    }
300→    initializeFeatures();
301→  }
302→}
303→
304→// Main initialization logic
305→(function () {
306→  try {
307→    if (!hasValidExtensionContext()) return;
308→
309→    const onUnhandledRejection = (event: PromiseRejectionEvent) => {
310→      if (isExtensionContextInvalidatedError(event.reason)) {
311→        event.preventDefault();
312→      }
313→    };
314→    const onWindowError = (event: ErrorEvent) => {
315→      if (isExtensionContextInvalidatedError(event.error ?? event.message)) {
316→        event.preventDefault();
317→      }
318→    };
319→    window.addEventListener('unhandledrejection', onUnhandledRejection);
320→    window.addEventListener('error', onWindowError);
321→
322→    // Quick check: only run on supported websites
323→    const hostname = location.hostname.toLowerCase();
324→    const isSupportedSite =
325→      hostname.includes('gemini.google.com') ||
326→      hostname.includes('business.gemini.google') ||
327→      hostname.includes('aistudio.google.com') ||
328→      hostname.includes('aistudio.google.cn');
329→
330→    // Initialize KaTeX configuration early to suppress Unicode warnings
331→    // This must run before any formulas are rendered on the page
332→    if (isSupportedSite) {
333→      initKaTeXConfig();
334→      // Initialize i18n early to ensure translations are available
335→      initI18n().catch((e) => console.error('[Gemini Voyager] i18n init error:', e));
336→    }
337→
338→    // If not a known site, check if it's a custom website (async)
339→    if (!isSupportedSite) {
340→      // For unknown sites, check storage asynchronously
341→      chrome.storage?.sync?.get({ gvPromptCustomWebsites: [] }, (result) => {
342→        const customWebsites = Array.isArray(result?.gvPromptCustomWebsites)
343→          ? result.gvPromptCustomWebsites
344→          : [];
345→        const currentHost = hostname.replace(/^www\./, '');
346→
347→        const isCustomSite = customWebsites.some((website: string) => {
348→          const normalizedWebsite = website.toLowerCase().replace(/^www\./, '');
349→          return currentHost === normalizedWebsite || currentHost.endsWith('.' + normalizedWebsite);
350→        });
351→
352→        if (isCustomSite) {
353→          console.log('[Gemini Voyager] Custom website detected:', hostname);
354→          initializeFeatures();
355→        } else {
356→          // Not a supported site, exit early
357→          console.log('[Gemini Voyager] Not a supported website, skipping initialization');
358→        }
359→      });
360→      return;
361→    }
362→
363→    const delay = getInitializationDelay();
364→
365→    if (delay === 0) {
366→      // Immediate initialization for foreground tabs
367→      initializeFeatures();
368→    } else {
369→      // Delayed initialization for background tabs
370→      initializationTimer = window.setTimeout(() => {
371→        initializationTimer = null;
372→        initializeFeatures();
373→      }, delay);
374→    }
375→
376→    // Listen for visibility changes to handle tab switching
377→    document.addEventListener('visibilitychange', handleVisibilityChange);
378→
379→    // Setup cleanup on page unload to prevent memory leaks
380→    window.addEventListener('beforeunload', () => {
381→      try {
382→        window.removeEventListener('unhandledrejection', onUnhandledRejection);
383→        window.removeEventListener('error', onWindowError);
384→        if (folderManagerInstance) {
385→          folderManagerInstance.destroy();
386→          folderManagerInstance = null;
387→        }
388→        if (promptManagerInstance) {
389→          promptManagerInstance.destroy();
390→          promptManagerInstance = null;
391→        }
392→        if (quoteReplyCleanup) {
393→          quoteReplyCleanup();
394→          quoteReplyCleanup = null;
395→        }
396→        if (sendBehaviorCleanup) {
397→          sendBehaviorCleanup();
398→          sendBehaviorCleanup = null;
399→        }
400→      } catch (e) {
401→        if (isExtensionContextInvalidatedError(e)) {
402→          return;
403→        }
404→        console.error('[Gemini Voyager] Cleanup error:', e);
405→      }
406→    });
407→  } catch (e) {
408→    if (isExtensionContextInvalidatedError(e)) {
409→      return;
410→    }
411→    console.error('[Gemini Voyager] Fatal initialization error:', e);
412→  }
413→})();
