  1→/**
  2→ * Sidebar Auto-Hide Feature for Gemini
  3→ *
  4→ * When enabled, the sidebar automatically collapses when the mouse leaves,
  5→ * and expands when the mouse enters.
  6→ *
  7→ * Uses the `side-nav-menu-button` to toggle sidebar state.
  8→ */
  9→
 10→const STYLE_ID = 'gv-sidebar-auto-hide-style';
 11→const STORAGE_KEY = 'gvSidebarAutoHide';
 12→
 13→// Debounce delay to avoid rapid toggling
 14→const LEAVE_DELAY_MS = 500;
 15→const ENTER_DELAY_MS = 300;
 16→// Interval to check for sidenav element reappearing
 17→const SIDENAV_CHECK_INTERVAL_MS = 1000;
 18→// Debounce delay for resize events
 19→const RESIZE_DEBOUNCE_MS = 200;
 20→// Pause duration after menu item click (wait for dialog to appear)
 21→const MENU_CLICK_PAUSE_MS = 1500;
 22→const CUSTOM_POPUP_SELECTORS = [
 23→  '.gv-folder-dialog',
 24→  '.gv-folder-dialog-overlay',
 25→  '.gv-folder-confirm-dialog',
 26→  '.gv-folder-import-dialog',
 27→  '.gv-folder-menu',
 28→  '.gv-color-picker-dialog',
 29→];
 30→
 31→let enabled = false;
 32→let leaveTimeoutId: number | null = null;
 33→let enterTimeoutId: number | null = null;
 34→let sidenavElement: HTMLElement | null = null;
 35→let observer: MutationObserver | null = null;
 36→let resizeHandler: (() => void) | null = null;
 37→let resizeDebounceTimer: number | null = null;
 38→let sidenavCheckTimer: number | null = null;
 39→let menuClickHandler: ((e: Event) => void) | null = null;
 40→// Track whether sidebar was collapsed by our feature (to avoid fighting with user)
 41→let autoCollapsed = false;
 42→// Temporarily pause auto-collapse after menu actions
 43→let pausedUntil = 0;
 44→
 45→function isElementVisible(element: HTMLElement): boolean {
 46→  const style = window.getComputedStyle(element);
 47→  if (style.display === 'none' || style.visibility === 'hidden') {
 48→    return false;
 49→  }
 50→
 51→  const rect = element.getBoundingClientRect();
 52→  return rect.width > 0 || rect.height > 0;
 53→}
 54→
 55→/**
 56→ * CSS to enable smooth transitions for the sidebar collapse/expand
 57→ */
 58→function getTransitionStyle(): string {
 59→  return `
 60→    /* Smooth transition for sidebar auto-hide */
 61→    bard-sidenav,
 62→    bard-sidenav side-navigation-content,
 63→    bard-sidenav side-navigation-content > div {
 64→      transition: width 0.25s ease, transform 0.25s ease !important;
 65→    }
 66→  `;
 67→}
 68→
 69→/**
 70→ * Insert transition CSS
 71→ */
 72→function insertTransitionStyle(): void {
 73→  if (document.getElementById(STYLE_ID)) return;
 74→
 75→  const style = document.createElement('style');
 76→  style.id = STYLE_ID;
 77→  style.textContent = getTransitionStyle();
 78→  document.documentElement.appendChild(style);
 79→}
 80→
 81→/**
 82→ * Remove transition CSS
 83→ */
 84→function removeTransitionStyle(): void {
 85→  const style = document.getElementById(STYLE_ID);
 86→  if (style) style.remove();
 87→}
 88→
 89→/**
 90→ * Find the sidebar toggle button
 91→ * Uses the selector provided by user: side-nav-menu-button button
 92→ */
 93→function findToggleButton(): HTMLButtonElement | null {
 94→  // Primary: Use data-test-id attribute
 95→  const btn = document.querySelector<HTMLButtonElement>(
 96→    'button[data-test-id="side-nav-menu-button"]',
 97→  );
 98→  if (btn) return btn;
 99→
100→  // Fallback: Find button inside side-nav-menu-button component
101→  const sideNavMenuButton = document.querySelector('side-nav-menu-button');
102→  if (sideNavMenuButton) {
103→    return sideNavMenuButton.querySelector<HTMLButtonElement>('button');
104→  }
105→
106→  return null;
107→}
108→
109→/**
110→ * Check if sidebar is currently collapsed
111→ */
112→function isSidebarCollapsed(): boolean {
113→  // Method 1: Check mat-sidenav-opened class on body
114→  if (document.body.classList.contains('mat-sidenav-opened')) {
115→    return false; // opened = not collapsed
116→  }
117→
118→  // Method 2: Check side-navigation-content collapsed class
119→  const sideContent = document.querySelector('bard-sidenav side-navigation-content > div');
120→  if (sideContent?.classList.contains('collapsed')) {
121→    return true;
122→  }
123→
124→  // Method 3: Check the actual width of sidenav
125→  const sidenav = document.querySelector<HTMLElement>('bard-sidenav');
126→  if (sidenav) {
127→    const width = sidenav.getBoundingClientRect().width;
128→    // Collapsed sidebar is typically < 80px
129→    if (width < 80) return true;
130→  }
131→
132→  return false;
133→}
134→
135→/**
136→ * Check if sidebar is visible (exists and has dimensions)
137→ */
138→function isSidebarVisible(): boolean {
139→  const sidenav = document.querySelector<HTMLElement>('bard-sidenav');
140→  if (!sidenav) return false;
141→
142→  const rect = sidenav.getBoundingClientRect();
143→  // Sidebar is visible if it has width and height
144→  return rect.width > 0 && rect.height > 0;
145→}
146→
147→/**
148→ * Check if auto-collapse is currently paused
149→ */
150→function isPaused(): boolean {
151→  return Date.now() < pausedUntil;
152→}
153→
154→/**
155→ * Pause auto-collapse for a duration
156→ */
157→function pauseAutoCollapse(durationMs: number): void {
158→  pausedUntil = Date.now() + durationMs;
159→}
160→
161→/**
162→ * Check if there's a visible popup/dialog/menu open that should prevent sidebar collapse
163→ * This includes delete confirmation dialogs, context menus, etc.
164→ */
165→function isPopupOrDialogOpen(): boolean {
166→  // Check for Angular Material dialogs - must be visible
167→  const matDialogs = document.querySelectorAll<HTMLElement>('.mat-mdc-dialog-container');
168→  for (const dialog of matDialogs) {
169→    if (isElementVisible(dialog)) return true;
170→  }
171→
172→  // Check for Angular Material menus - must be visible
173→  const matMenus = document.querySelectorAll<HTMLElement>('.mat-mdc-menu-panel');
174→  for (const menu of matMenus) {
175→    if (isElementVisible(menu)) return true;
176→  }
177→
178→  // Check for Gemini Voyager popup elements
179→  for (const selector of CUSTOM_POPUP_SELECTORS) {
180→    const customPopups = document.querySelectorAll<HTMLElement>(selector);
181→    for (const popup of customPopups) {
182→      if (isElementVisible(popup)) return true;
183→    }
184→  }
185→
186→  return false;
187→}
188→
189→/**
190→ * Check if mouse is currently over the sidebar or any related popup element
191→ */
192→function isMouseOverSidebarArea(): boolean {
193→  // Check if mouse is over the sidenav
194→  if (sidenavElement?.matches(':hover')) return true;
195→
196→  // Check if mouse is over visible dialogs/menus
197→  const matDialogs = document.querySelectorAll<HTMLElement>('.mat-mdc-dialog-container');
198→  for (const dialog of matDialogs) {
199→    if (dialog.matches(':hover')) return true;
200→  }
201→
202→  const matMenus = document.querySelectorAll<HTMLElement>('.mat-mdc-menu-panel');
203→  for (const menu of matMenus) {
204→    if (menu.matches(':hover')) return true;
205→  }
206→
207→  for (const selector of CUSTOM_POPUP_SELECTORS) {
208→    const customPopups = document.querySelectorAll<HTMLElement>(selector);
209→    for (const popup of customPopups) {
210→      if (popup.matches(':hover')) return true;
211→    }
212→  }
213→
214→  return false;
215→}
216→
217→/**
218→ * Handle click on menu items - pause auto-collapse to wait for potential dialogs
219→ */
220→function handleMenuClick(e: Event): void {
221→  if (!enabled) return;
222→
223→  const target = e.target as HTMLElement;
224→
225→  // Check if clicked on a menu item (especially delete actions)
226→  const menuItem = target.closest('[role="menuitem"], [role="menuitemradio"], .mat-mdc-menu-item');
227→  if (menuItem) {
228→    // Pause auto-collapse to allow dialog to appear
229→    pauseAutoCollapse(MENU_CLICK_PAUSE_MS);
230→    return;
231→  }
232→
233→  // Check if clicked on any button inside the sidebar that might trigger a dialog
