292→/**
293→ * Handle mouse enter on sidebar
294→ */
295→function handleMouseEnter(): void {
296→  if (!enabled) return;
297→
298→  // Cancel any pending collapse
299→  if (leaveTimeoutId !== null) {
300→    window.clearTimeout(leaveTimeoutId);
301→    leaveTimeoutId = null;
302→  }
303→
304→  // Debounce the expand to avoid accidental triggers while crossing screens
305→  if (enterTimeoutId !== null) {
306→    window.clearTimeout(enterTimeoutId);
307→  }
308→
309→  enterTimeoutId = window.setTimeout(() => {
310→    enterTimeoutId = null;
311→    if (!enabled) return;
312→    expandSidebar();
