324→    window.clearTimeout(enterTimeoutId);
325→    enterTimeoutId = null;
326→  }
327→
328→  // Debounce the collapse to avoid accidental triggers
329→  if (leaveTimeoutId !== null) {
330→    window.clearTimeout(leaveTimeoutId);
331→  }
332→
333→  leaveTimeoutId = window.setTimeout(() => {
334→    leaveTimeoutId = null;
335→
336→    // Double-check conditions before collapsing
337→    if (!enabled) return;
338→
339→    collapseSidebar();
