343→/**
344→ * Get the sidenav container element
345→ */
346→function getSidenavElement(): HTMLElement | null {
347→  return document.querySelector<HTMLElement>('bard-sidenav');
348→}
349→
350→/**
351→ * Attach event listeners to the sidenav element
352→ */
353→function attachEventListeners(): boolean {
354→  const sidenav = getSidenavElement();
355→  if (!sidenav) return false;
356→
357→  // Check if sidebar is actually visible (not hidden due to responsive design)
358→  if (!isSidebarVisible()) return false;
359→
360→  // Already attached to this element
361→  if (sidenav === sidenavElement) return true;
362→
363→  // Remove old listeners if element changed
364→  if (sidenavElement) {
365→    sidenavElement.removeEventListener('mouseenter', handleMouseEnter);
366→    sidenavElement.removeEventListener('mouseleave', handleMouseLeave);
367→  }
368→
369→  sidenavElement = sidenav;
370→  sidenav.addEventListener('mouseenter', handleMouseEnter);
371→  sidenav.addEventListener('mouseleave', handleMouseLeave);
372→  return true;
373→}
374→
375→/**
376→ * Remove event listeners from the sidenav element
377→ */
378→function detachEventListeners(): void {
379→  if (sidenavElement) {
380→    sidenavElement.removeEventListener('mouseenter', handleMouseEnter);
381→    sidenavElement.removeEventListener('mouseleave', handleMouseLeave);
382→    sidenavElement = null;
383→  }
384→}
385→
386→/**
387→ * Check and reattach event listeners if sidenav element changed or reappeared
388→ */
389→function checkAndReattach(): void {
390→  if (!enabled) return;
391→
392→  const currentSidenav = getSidenavElement();
393→
394→  // If we have a reference but it's no longer in DOM, clear it
395→  if (sidenavElement && !sidenavElement.isConnected) {
396→    detachEventListeners(); // properly remove listeners and null the reference
397→    autoCollapsed = false;
398→  }
399→
400→  // If sidenav exists but is NOT visible (narrow window), clear the reference
401→  // so that when it becomes visible again we treat it as a fresh element.
402→  if (sidenavElement && !isSidebarVisible()) {
403→    detachEventListeners();
404→    return;
405→  }
406→
407→  // If sidenav exists and is visible, try to attach
408→  if (currentSidenav && isSidebarVisible()) {
409→    // Reattach if element changed OR if we lost our reference (e.g. after resize)
410→    if (currentSidenav !== sidenavElement) {
411→      attachEventListeners();
412→    }
413→  }
414→}
415→
416→/**
417→ * Handle window resize - reattach listeners if sidebar reappears (with debounce)
418→ */
419→function handleResize(): void {
420→  if (!enabled) return;
421→
422→  // Debounce resize handling
423→  if (resizeDebounceTimer !== null) {
424→    window.clearTimeout(resizeDebounceTimer);
425→  }
426→
427→  resizeDebounceTimer = window.setTimeout(() => {
428→    resizeDebounceTimer = null;
429→    checkAndReattach();
430→
431→    // Gemini's layout transitions may take longer than our debounce.
432→    // Schedule a secondary check to catch late DOM changes.
433→    setTimeout(() => {
434→      if (enabled) checkAndReattach();
435→    }, 600);
436→  }, RESIZE_DEBOUNCE_MS);
437→}
438→
439→/**
440→ * Start periodic check for sidenav element
441→ */
442→function startSidenavCheck(): void {
443→  if (sidenavCheckTimer !== null) return;
444→
445→  sidenavCheckTimer = window.setInterval(() => {
446→    checkAndReattach();
447→  }, SIDENAV_CHECK_INTERVAL_MS);
448→}
449→
450→/**
451→ * Stop periodic check for sidenav element
452→ */
453→function stopSidenavCheck(): void {
454→  if (sidenavCheckTimer !== null) {
455→    window.clearInterval(sidenavCheckTimer);
456→    sidenavCheckTimer = null;
457→  }
458→}
459→
460→/**
461→ * Enable the auto-hide feature
462→ */
463→function enable(): void {
464→  if (enabled) return;
465→  enabled = true;
466→  autoCollapsed = false;
467→  pausedUntil = 0;
468→
469→  insertTransitionStyle();
470→  attachEventListeners();
471→
472→  // Start observing for DOM changes (in case sidenav is lazily loaded)
473→  if (!observer) {
474→    observer = new MutationObserver(() => {
475→      if (enabled) {
476→        checkAndReattach();
477→      }
478→    });
479→
480→    observer.observe(document.body, { childList: true, subtree: true });
481→  }
482→
483→  // Listen for resize events to handle responsive changes
484→  if (!resizeHandler) {
485→    resizeHandler = handleResize;
486→    window.addEventListener('resize', resizeHandler);
487→  }
488→
489→  // Listen for clicks on menu items to pause auto-collapse
490→  if (!menuClickHandler) {
491→    menuClickHandler = handleMenuClick;
492→    document.addEventListener('click', menuClickHandler, true);
493→  }
494→
495→  // Start periodic check for sidenav element reappearing
496→  startSidenavCheck();
497→
498→  // Initial collapse if mouse is not on sidebar and no popup is open
499→  setTimeout(() => {
500→    if (enabled && sidenavElement && !sidenavElement.matches(':hover') && !isPopupOrDialogOpen()) {
501→      collapseSidebar();
502→    }
503→  }, 500);
504→}
505→
506→/**
507→ * Disable the auto-hide feature
508→ */
509→function disable(): void {
510→  if (!enabled) return;
511→  enabled = false;
512→
513→  // Cancel any pending expand
514→  if (enterTimeoutId !== null) {
515→    window.clearTimeout(enterTimeoutId);
516→    enterTimeoutId = null;
517→  }
518→
519→  // Cancel any pending collapse
520→  if (leaveTimeoutId !== null) {
521→    window.clearTimeout(leaveTimeoutId);
522→    leaveTimeoutId = null;
523→  }
524→
525→  // Cancel any pending resize debounce
526→  if (resizeDebounceTimer !== null) {
527→    window.clearTimeout(resizeDebounceTimer);
528→    resizeDebounceTimer = null;
529→  }
530→
531→  // Stop periodic check
532→  stopSidenavCheck();
533→
534→  // If we auto-collapsed the sidebar, expand it back when disabled
535→  if (autoCollapsed && isSidebarCollapsed()) {
536→    clickToggleButton();
537→  }
538→  autoCollapsed = false;
539→  pausedUntil = 0;
540→
541→  detachEventListeners();
542→  removeTransitionStyle();
543→
544→  if (observer) {
545→    observer.disconnect();
546→    observer = null;
547→  }
548→
549→  if (resizeHandler) {
550→    window.removeEventListener('resize', resizeHandler);
551→    resizeHandler = null;
552→  }
553→
554→  if (menuClickHandler) {
555→    document.removeEventListener('click', menuClickHandler, true);
556→    menuClickHandler = null;
557→  }
558→}
