560→/**
561→ * Initialize and start the sidebar auto-hide feature
562→ */
563→export function startSidebarAutoHide(): void {
564→  // 1) Read initial setting
565→  try {
566→    chrome.storage?.sync?.get({ [STORAGE_KEY]: false }, (res) => {
567→      const isEnabled = res?.[STORAGE_KEY] === true;
568→      if (isEnabled) {
569→        enable();
570→      }
571→    });
572→  } catch (e) {
573→    console.error('[Gemini Voyager] Failed to get sidebar auto-hide setting:', e);
574→  }
575→
576→  // 2) Respond to storage changes
577→  try {
578→    chrome.storage?.onChanged?.addListener((changes, area) => {
579→      if (area === 'sync' && changes[STORAGE_KEY]) {
580→        const isEnabled = changes[STORAGE_KEY].newValue === true;
581→        if (isEnabled) {
582→          enable();
583→        } else {
584→          disable();
585→        }
586→      }
587→    });
588→  } catch (e) {
589→    console.error('[Gemini Voyager] Failed to add storage listener for sidebar auto-hide:', e);
590→  }
591→
592→  // 3) Cleanup on page unload
593→  window.addEventListener('beforeunload', () => {
594→    disable();
595→  });
596→}
