  40→const LEGACY_BASELINE_PX = 1200; // used to migrate old px widths to %
  41→const pxFromPercent = (percent: number) => (percent / 100) * LEGACY_BASELINE_PX;
  42→
  43→const clampNumber = (value: number, min: number, max: number) =>
  44→  Math.min(max, Math.max(min, Math.round(value)));
  45→
  46→const clampPercent = (value: number, min: number, max: number) =>
  47→  Math.min(max, Math.max(min, Math.round(value)));
  48→
  49→const normalizePercent = (
  50→  value: number,
  51→  fallback: number,
  52→  min: number,
  53→  max: number,
  54→  legacyBaselinePx: number,
  55→) => {
  56→  if (!Number.isFinite(value)) return fallback;
  57→  if (value > max) {
  58→    const approx = (value / legacyBaselinePx) * 100;
  59→    return clampPercent(approx, min, max);
  60→  }
  61→  return clampPercent(value, min, max);
  62→};
