  71→  defaultValue: 26,
  72→  legacyBaselinePx: LEGACY_BASELINE_PX,
  73→};
  74→const SIDEBAR_PX = {
  75→  min: Math.round(pxFromPercent(SIDEBAR_PERCENT.min)),
  76→  max: Math.round(pxFromPercent(SIDEBAR_PERCENT.max)),
  77→  defaultValue: Math.round(pxFromPercent(SIDEBAR_PERCENT.defaultValue)),
