  85→const clampSidebarPx = (value: number) => clampNumber(value, SIDEBAR_PX.min, SIDEBAR_PX.max);
  86→const normalizeSidebarPx = (value: number) => {
  87→  if (!Number.isFinite(value)) return SIDEBAR_PX.defaultValue;
