  1→/**
  2→ * Snow Effect for Gemini
  3→ *
  4→ * When enabled, renders a fullscreen canvas snow animation.
  5→ * Uses `pointer-events: none` so it never blocks page interactions.
  6→ * Pauses when the tab is hidden to save CPU.
  7→ */
  8→
  9→const CANVAS_ID = 'gv-snow-effect-canvas';
 10→const STORAGE_KEY = 'gvSnowEffect';
 11→const SNOWFLAKE_COUNT = 100;
 12→
 13→interface Snowflake {
 14→  x: number;
 15→  y: number;
 16→  radius: number;
 17→  opacity: number;
 18→  speedY: number;
 19→  drift: number;
 20→  phase: number;
 21→}
 22→
 23→let enabled = false;
 24→let canvas: HTMLCanvasElement | null = null;
 25→let ctx: CanvasRenderingContext2D | null = null;
 26→let animationFrameId: number | null = null;
 27→let snowflakes: Snowflake[] = [];
 28→let resizeHandler: (() => void) | null = null;
 29→let visibilityHandler: (() => void) | null = null;
 30→
 31→function createSnowflake(canvasWidth: number, canvasHeight: number, randomY = false): Snowflake {
 32→  return {
 33→    x: Math.random() * canvasWidth,
 34→    y: randomY ? Math.random() * canvasHeight : -Math.random() * canvasHeight,
 35→    radius: 2 + Math.random() * 4,
 36→    opacity: 0.4 + Math.random() * 0.6,
 37→    speedY: 0.5 + Math.random() * 1.5,
 38→    drift: 0.3 + Math.random() * 0.7,
 39→    phase: Math.random() * Math.PI * 2,
 40→  };
 41→}
 42→
 43→function initSnowflakes(width: number, height: number): void {
 44→  snowflakes = [];
 45→  for (let i = 0; i < SNOWFLAKE_COUNT; i++) {
 46→    snowflakes.push(createSnowflake(width, height, true));
 47→  }
 48→}
 49→
 50→function updateAndDraw(time: number): void {
 51→  if (!ctx || !canvas) return;
 52→
 53→  const { width, height } = canvas;
 54→  ctx.clearRect(0, 0, width, height);
 55→
 56→  for (const flake of snowflakes) {
 57→    flake.y += flake.speedY;
 58→    flake.x += Math.sin(flake.phase + time * 0.001) * flake.drift;
 59→
 60→    // Recycle snowflake when it falls off-screen
 61→    if (flake.y > height + flake.radius) {
 62→      flake.y = -flake.radius;
 63→      flake.x = Math.random() * width;
 64→    }
 65→
 66→    // Wrap horizontal position
 67→    if (flake.x > width + flake.radius) {
 68→      flake.x = -flake.radius;
 69→    } else if (flake.x < -flake.radius) {
 70→      flake.x = width + flake.radius;
 71→    }
 72→
 73→    ctx.beginPath();
 74→    ctx.arc(flake.x, flake.y, flake.radius, 0, Math.PI * 2);
 75→    ctx.fillStyle = `rgba(255, 255, 255, ${flake.opacity})`;
 76→    ctx.fill();
 77→  }
 78→
 79→  animationFrameId = requestAnimationFrame(updateAndDraw);
 80→}
 81→
 82→function resizeCanvas(): void {
 83→  if (!canvas) return;
 84→  canvas.width = window.innerWidth;
 85→  canvas.height = window.innerHeight;
 86→}
 87→
 88→function startAnimation(): void {
 89→  if (animationFrameId !== null) return;
 90→  animationFrameId = requestAnimationFrame(updateAndDraw);
 91→}
 92→
 93→function stopAnimation(): void {
 94→  if (animationFrameId !== null) {
 95→    cancelAnimationFrame(animationFrameId);
 96→    animationFrameId = null;
 97→  }
 98→}
 99→
100→function handleVisibilityChange(): void {
101→  if (document.visibilityState === 'visible') {
102→    startAnimation();
103→  } else {
104→    stopAnimation();
105→  }
106→}
107→
108→function enable(): void {
109→  if (enabled) return;
110→  enabled = true;
111→
112→  canvas = document.createElement('canvas');
113→  canvas.id = CANVAS_ID;
114→  canvas.style.cssText =
115→    'position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:2147483647;';
116→  document.documentElement.appendChild(canvas);
117→
118→  ctx = canvas.getContext('2d');
119→  if (!ctx) {
120→    disable();
121→    return;
122→  }
123→
124→  resizeCanvas();
125→  initSnowflakes(canvas.width, canvas.height);
126→  startAnimation();
127→
128→  resizeHandler = resizeCanvas;
129→  window.addEventListener('resize', resizeHandler);
130→
131→  visibilityHandler = handleVisibilityChange;
132→  document.addEventListener('visibilitychange', visibilityHandler);
133→}
134→
135→function disable(): void {
136→  if (!enabled) return;
137→  enabled = false;
138→
139→  stopAnimation();
140→
141→  if (resizeHandler) {
142→    window.removeEventListener('resize', resizeHandler);
143→    resizeHandler = null;
144→  }
145→
146→  if (visibilityHandler) {
147→    document.removeEventListener('visibilitychange', visibilityHandler);
148→    visibilityHandler = null;
149→  }
150→
151→  if (canvas) {
152→    canvas.remove();
153→    canvas = null;
154→  }
155→
156→  ctx = null;
157→  snowflakes = [];
158→}
159→
160→/**
161→ * Initialize and start the snow effect feature
162→ */
163→export function startSnowEffect(): void {
164→  // 1) Read initial setting
165→  try {
166→    chrome.storage?.sync?.get({ [STORAGE_KEY]: false }, (res) => {
167→      if (res?.[STORAGE_KEY] === true) {
168→        enable();
169→      }
170→    });
171→  } catch (e) {
172→    console.error('[Gemini Voyager] Failed to get snow effect setting:', e);
173→  }
174→
175→  // 2) Respond to storage changes
176→  try {
177→    chrome.storage?.onChanged?.addListener((changes, area) => {
178→      if (area === 'sync' && changes[STORAGE_KEY]) {
179→        if (changes[STORAGE_KEY].newValue === true) {
180→          enable();
181→        } else {
182→          disable();
183→        }
184→      }
185→    });
186→  } catch (e) {
187→    console.error('[Gemini Voyager] Failed to add storage listener for snow effect:', e);
188→  }
189→
190→  // 3) Cleanup on page unload
191→  window.addEventListener('beforeunload', () => {
192→    disable();
193→  });
194→}
